@startuml
skinparam backgroundColor #cfd2ff
skinparam shadowing false
skinparam packageStyle rectangle
skinparam classAttributeIconSize 0
skinparam class {
  BackgroundColor #f7f7f7
  BorderColor #666666
}
skinparam note {
  BackgroundColor #fff7c7
  BorderColor #666666
}

package "Bean" as Bean #cfd2ff {

class lable {
  int ID
  String info
}

class borrowHis {
  Date returnDate
  Boolean flag
}

class user {
  String ID
  String pwd
  Date createTime
  byte status
}

class ticket {
  String title
  String info
  String adminID
}

class bookDetList {
  String ID
  Date borrowDate
  short deadline
  byte status
}

class root

class borrower {
  String firstName
  String lastName
  String IDCardNo
  String email
  String m_phoneNumber
  String creditRating
}

class admin {
  String firstName
  String lastName
  String email
  Boolean root
}

class bookDetListInfo {
  byte number
}

class book {
  String ISBN
  String name
  String Label
  String logo
  String info
  float price
  String publisher
  String author
  Date publishDate
  short stock
  short Number
}

note right of lable
图书分类,用来控制添加或修改图书时
控制器选项范围,不与book建立直接联系
end note

root -|> user : 继承
borrower -|> user : 继承
admin -|> user : 继承

admin "1" -- "N" ticket : 管理

user "1" -- "N" bookDetList : 拥有或管理

borrowHis *-- bookDetList : 包含
borrowHis -|> bookDetList : 继承

bookDetList *-- bookDetListInfo : 拥有
bookDetListInfo "1" -- "1" book : 记录

}
@enduml
